import { isBefore } from 'date-fns';

import { formatDate } from '@dynatrace-sdk/units';

import { TimeResolution } from './subheaders/TimeResolution.js';
import { SeriesDisplayMode, TooltipItem } from '../../../../types/tooltip.js';
import { FormattedTimeframe } from '../../utils/FormattedTimeframe.js';
import {
  StyledChartTooltipHeader,
  StyledFormattedTimeframe,
  StyledTitleContainer,
} from '../components/InteractiveChartTooltip.styles.js';
import { SeriesBasedContent } from '../contents/SeriesBasedContent.js';

interface TimebasedTooltipHeaderProps {
  timeframe: [Date, Date?];
  item?: TooltipItem;
  seriesDisplayMode?: SeriesDisplayMode;
}

export const TimebasedTooltipHeader = ({
  timeframe: [from, timeframeTo],
  item,
  seriesDisplayMode = 'single-line',
}: TimebasedTooltipHeaderProps) => {
  const to =
    timeframeTo !== undefined && isBefore(from, timeframeTo)
      ? timeframeTo
      : undefined;

  return (
    (<StyledChartTooltipHeader>
      <StyledTitleContainer gap={8}>
        {to && <TimeResolution from={from} to={to} />}
        <StyledFormattedTimeframe>
          {to !== undefined ? (
            (<FormattedTimeframe
              data-testid="formatted-timeframe"
              from={from}
              to={to}
            />)
          ) : (
            formatDate(from, {
              day: '2-digit',
              month: 'short',
              year:
                from.getFullYear() === new Date().getFullYear()
                  ? undefined
                  : 'numeric',
              hour: '2-digit',
              minute: '2-digit',
              second: from.getSeconds() === 0 ? undefined : 'numeric',
            })
          )}
        </StyledFormattedTimeframe>
      </StyledTitleContainer>
      {item && (
        <SeriesBasedContent
          item={item}
          highlighted
          seriesDisplayMode={seriesDisplayMode}
        />
      )}
    </StyledChartTooltipHeader>)
  );
};
